class Solution:
    def largestValsFromLabels(self, values, labels, numWanted, useLimit):
        items = sorted(zip(values, labels), reverse=True)
        used = {}
        total = 0
        taken = 0
        for v, lab in items:
            if taken >= numWanted:
                break
            if used.get(lab, 0) < useLimit:
                total += v
                used[lab] = used.get(lab, 0) + 1
                taken += 1
        return total

