class Solution:
    def largestValsFromLabels(self, values, labels, numWanted, useLimit):
        order = sorted(range(len(values)), key=lambda i: values[i], reverse=True)
        count = {}
        total = 0
        picked = 0
        for i in order:
            if picked == numWanted:
                break
            lab = labels[i]
            c = count.get(lab, 0)
            if c < useLimit:
                total += values[i]
                count[lab] = c + 1
                picked += 1
        return total

