var largestValsFromLabels = function(values, labels, numWanted, useLimit) {
    const idx = values.map((_, i) => i);
    idx.sort((a, b) => values[b] - values[a]);
    const count = new Map();
    let total = 0, picked = 0;
    for (const i of idx) {
        if (picked === numWanted) break;
        const lab = labels[i];
        const c = count.get(lab) || 0;
        if (c < useLimit) {
            total += values[i];
            count.set(lab, c + 1);
            picked += 1;
        }
    }
    return total;
};
